    wrongAnswerExplanations: {
      A: 'This choice presents permeable pavement\'s benefits and Rotterdam data — both are solution evidence, not problem presentation.',
      C: 'Cost-benefit framing describes the economic case for a solution; it does not present the environmental problem the solution addresses.',
      D: 'This choice introduces the Rotterdam pilot alongside the problem, mixing problem presentation with solution evidence in a single sentence — violating the task\'s instruction.',
    },
    teachingPoint: 'When a rhetorical task specifies what to include AND what to exclude (here: present the problem, not the solution), eliminate any choice that introduces excluded material even if the excluded material is accurate. The task\'s boundary conditions are as important as the content requirements.',
    relatedSkills: ['Transitions', 'Text Structure and Purpose'],
